  async insertMany(req: CreatePriceSettingInput[], hotel?: Hotel) {
    const items = [];
    for (const input of req) {
      const item = new PriceSetting();
      Object.assign(item, input);
      item.name = this.getNameRatePlan(
        input.condition,
        input.mealPlan,
        input.room.localName,
        input.amount,
        input.unitType,
      );
      if (hotel) item.hotel = hotel;
      items.push(item);
    }

    const savedItems = await this.repo.saveMany(items);
    await Promise.all(savedItems.map(item => this.syncRateCalendar(item)));
    return savedItems;
  }

  async delete(id: number) {
    const entity = await this.repo.findById(id, { relations: ['hotel', 'room'] });
    if (!entity) throw new NotFoundError(ErrorCode.PRICE_SETTING_NOT_FOUND);
    const previousPeriods = this.clonePeriods(entity.periods);
    await this.repo.delete(id);
    entity.isActive = false;
    await this.syncRateCalendar(entity, previousPeriods);
  }
