  /**
   * Validate format của periods
   */
  private validatePeriodsFormat(periods: RangeDate[]) {
    if (!periods || !Array.isArray(periods) || periods.length === 0) {
      throw new BusinessLogicError(ErrorCode.PERIODS_REQUIRED);
    }

    for (const dateRange of periods) {
      if (!dateRange.startDate || !dateRange.endDate) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      const startDate = dayjs(dateRange.startDate);
      const endDate = dayjs(dateRange.endDate);

      if (!startDate.isValid() || !endDate.isValid()) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }

      if (startDate.isAfter(endDate)) {
        throw new BusinessLogicError(ErrorCode.PERIODS_INVALID);
      }
    }
  }

  /**
   * Check trùng lặp dựa trên:
   * - Loại phụ phí (type)
   * - Thị trường khách (countries)
   * - Loại ngày áp dụng (dayType)
   * - Mùa/Sự kiện (seasonId)
   *
   * Nếu các điều kiện trên trùng hoàn toàn thì check:
   * - Mùa trùng mùa (cùng seasonId)
   * - Mùa trùng thời gian tùy chỉnh (periods overlap)
   * - Sự kiện trùng sự kiện (cùng eventId trong season)
   */
  private async checkDuplicate(
    hotelId: number,
    type: SurchargeFeeType,
    countryIds: number[],
    dayType: string | null,
    seasonId: number | null,
    periods: RangeDate[],
    excludeId?: number,
  ) {
    const duplicate = await this.repo.findDuplicateStrict(
      hotelId,
      type,
      countryIds,
      dayType,
      seasonId,
      periods,
      excludeId,
    );

    if (duplicate) {
      throw new BusinessLogicError(ErrorCode.SURCHARGE_FEE_SETTING_DUPLICATE);
    }
  }

  async create(payload: CreateSurchargeFeeSettingInput) {
    const hotel = await this.hotelRepo.findById(payload.hotelId);
    if (!hotel) throw new NotFoundError(ErrorCode.HOTEL_NOT_FOUND);

    const countries = await this.countryRepo.find({
      where: { id: In(payload.countries) },
    });
    if (!countries) throw new BusinessLogicError(ErrorCode.COUNTRY_NOT_FOUND);

    const entity = new SurchargeFeeSetting();
    entity.countries = countries;
    entity.type = payload.type;
    entity.unitType = payload.unitType;
    entity.amount = payload.amount;
    entity.hotel = hotel;
    entity.ownerId = payload.ownerId;
    entity.createdBy = payload.createdBy;
    entity.dayType = payload.dayType;

    if (payload.seasonIds?.length > 0) {
      const seasons = await this.seasonRepo.find({ where: { id: In(payload.seasonIds) } });
      if (!seasons.length) throw new NotFoundError(ErrorCode.SEASON_NOT_FOUND);

      const countryIds = countries.map(c => c.id).sort((a, b) => a - b);

      // Check duplicate cho từng season
      for (const season of seasons) {
        this.validatePeriodsFormat(season.periods);
        await this.checkDuplicate(
          entity.hotel.id,
          entity.type,
          countryIds,
          entity.dayType,
          season.id,
          season.periods,
        );
      }

      const entities = seasons.map(season => ({
        ...entity,
        season,
        periods: season.periods,
      }));

      return this.repo.saveMany(entities);
    } else {
      entity.periods = payload.periods;
    }

    this.validatePeriodsFormat(entity.periods);
    const countryIds = countries.map(c => c.id).sort((a, b) => a - b);
    await this.checkDuplicate(entity.hotel.id, entity.type, countryIds, entity.dayType, null, entity.periods);

    return this.repo.save(entity);
  }

