  dayType: DayType | null;
  stayDates: HotelRoomStayDate[];
}

@Service()
export class RateCalendarRepository extends BaseOrmRepository<RateCalendar> {
  constructor(@Inject('dataSource') dataSource: DataSource) {
    super(dataSource, RateCalendar);
  }

  async deleteByHotelRoomAndDates(
    hotelId: number,
    roomId: number,
    stayDates: string[],
    options?: { priceSettingId?: number; mealPlan?: MealPlan },
  ) {
    if (!stayDates.length) return;
    const baseWhere = {
      hotelId,
      roomId,
      stayDate: In(stayDates),
    };
    if (options?.priceSettingId) {
      await this.repo.delete({
        ...baseWhere,
        priceSettingId: options.priceSettingId,
      });
      if (options?.mealPlan) {
        await this.repo.delete({
          ...baseWhere,
          priceSettingId: null,
          mealPlan: options.mealPlan,
        });
      }
      return;
    }
    if (options?.mealPlan) {
      await this.repo.delete({
        ...baseWhere,
        mealPlan: options.mealPlan,
      });
      return;
    }
    await this.repo.delete(baseWhere);
  }

  async aggregateByStayDates(
    hotelIds: number[],
    checkInDate: string,
    checkOutDate: string,
    limitHotels: number = 100,
  ): Promise<AggregatedRateRow[]> {
    if (!hotelIds.length) return [];
    const sql = `
      WITH stay_dates AS (
        SELECT generate_series($1::date, ($2::date - interval '1 day'), interval '1 day')::date AS stay_date
      ),
      normalized AS (
        SELECT DISTINCT ON (
          rc."hotelId",
          rc."roomId",
          rc."stayDate",
          COALESCE(rc."priceSettingId", -1),
          COALESCE(rc."mealPlan"::text, ''),
          COALESCE(rc."condition"::text, ''),
          COALESCE(rc."cancellationPeriod", -1),
          COALESCE(rc."cancellationPeriodUnitTime"::text, ''),
          COALESCE(rc."unitType"::text, ''),
          COALESCE(rc."amount", -1),
          COALESCE(rc."source", ''),
          COALESCE(rc."dayType"::text, '')
        )
          rc."hotelId",
          rc."roomId",
          rc."stayDate",
          rc."priceSettingId",
          rc."mealPlan",
          rc."source",
          rc."condition",
          rc."cancellationPeriod",
          rc."cancellationPeriodUnitTime",
          rc."unitType",
          rc."amount",
          rc."dayType",
          rc."baseRate",
          rc."availableRooms",
          rc."minStay"
        FROM rate_calendar rc
        JOIN stay_dates sd ON rc."stayDate" = sd.stay_date
        WHERE rc."hotelId" = ANY($3::int[]) AND rc.closed = false
        ORDER BY
          rc."hotelId",
          rc."roomId",
          rc."stayDate",
          COALESCE(rc."priceSettingId", -1),
          COALESCE(rc."mealPlan"::text, ''),
          COALESCE(rc."condition"::text, ''),
          COALESCE(rc."cancellationPeriod", -1),
          COALESCE(rc."cancellationPeriodUnitTime"::text, ''),
          COALESCE(rc."unitType"::text, ''),
          COALESCE(rc."amount", -1),
          COALESCE(rc."source", ''),
          COALESCE(rc."dayType"::text, ''),
          rc."baseRate" ASC
      ),

      aggregated AS (
        SELECT
          n."hotelId" AS "hotelId",
          n."roomId" AS "roomId",
          n."mealPlan" AS "mealPlan",
          n."source" AS "source",
          n."condition" AS "condition",
          n."cancellationPeriod" AS "cancellationPeriod",
          n."cancellationPeriodUnitTime" AS "cancellationPeriodUnitTime",
          n."unitType" AS "unitType",
          n."amount" AS "amount",
          n."dayType" AS "dayType",
          MIN(CASE WHEN n."dayType" = 'WEEKEND' THEN 0 ELSE 1 END) AS "dayTypePriority",
          SUM(n."baseRate") AS "baseTotal",
          MIN(n."availableRooms") AS "minAllotment",
          MIN(n."minStay") AS "minStay",
          jsonb_agg(
            jsonb_build_object(
              'stayDate', n."stayDate",
              'mealPlan', n."mealPlan",
              'baseRate', n."baseRate",
              'availableRooms', n."availableRooms",
              'priceSettingId' , n."priceSettingId",
              'minStay', n."minStay"
            )
            ORDER BY n."stayDate"
          ) AS "stayDates",
          r."maxCapacity" AS "maxCapacity",
          r."maxAdults" AS "maxAdults",
          r."maxChildren" AS "maxChildren"
        FROM normalized n
        JOIN room r ON r.id = n."roomId"
        GROUP BY
          n."hotelId",
          n."roomId",
          n."mealPlan",
          n."source",
          n."condition",
          n."cancellationPeriod",
          n."cancellationPeriodUnitTime",
          n."unitType",
          n."amount",
          n."dayType",
          r."maxCapacity",
          r."maxAdults",
          r."maxChildren"
        HAVING COUNT(*) = (SELECT COUNT(*) FROM stay_dates)
      ),
      ranked AS (
        SELECT *,
               ROW_NUMBER() OVER (PARTITION BY "hotelId" ORDER BY "dayTypePriority" ASC, "baseTotal" ASC) AS rn
        FROM aggregated
      ),
      top_hotels AS (
        SELECT "hotelId", "baseTotal"
        FROM ranked
        WHERE rn = 1
        ORDER BY "baseTotal" ASC
        LIMIT $4
      )
      SELECT a.*
      FROM aggregated a
      JOIN top_hotels th ON th."hotelId" = a."hotelId"
    `;

    const rows = await this.dataSource.query(sql, [checkInDate, checkOutDate, hotelIds, limitHotels]);
    return rows.map(row => {
      const rawStayDates =
        row.stayDates && typeof row.stayDates === 'string' ? JSON.parse(row.stayDates) : row.stayDates ?? [];
      return {
        hotelId: Number(row.hotelId),
        roomId: Number(row.roomId),
        baseTotal: Number(row.baseTotal),
        minAllotment: Number(row.minAllotment),
        minStay: Number(row.minStay),
        maxCapacity: Number(row.maxCapacity),
        maxAdults: Number(row.maxAdults),
        maxChildren: Number(row.maxChildren),
        mealPlan: row.mealPlan ?? null,
        source: row.source ?? null,
        condition: row.condition ?? null,
        cancellationPeriod: row.cancellationPeriod !== null ? Number(row.cancellationPeriod) : null,
        cancellationPeriodUnitTime: row.cancellationPeriodUnitTime ?? null,
        unitType: row.unitType ?? null,
